import{_ as s,c as i,o as a,a7 as e}from"./chunks/framework.DqBlM0ze.js";const E=JSON.parse('{"title":"Claude Code 使用实践：安装、配置与避坑","description":"","frontmatter":{"title":"Claude Code 使用实践：安装、配置与避坑","date":"2026-03-20T00:00:00.000Z","categories":["前端进阶","工作随记"],"tags":["claude","claude-code"]},"headers":[],"relativePath":"blogs/word/2026/20260320-claudecode使用.md","filePath":"blogs/word/2026/20260320-claudecode使用.md"}'),l={name:"blogs/word/2026/20260320-claudecode使用.md"},t=e(`<h1 id="claude-code-使用实践-安装、配置与避坑" tabindex="-1">Claude Code 使用实践：安装、配置与避坑 <a class="header-anchor" href="#claude-code-使用实践-安装、配置与避坑" aria-label="Permalink to &quot;Claude Code 使用实践：安装、配置与避坑&quot;">​</a></h1><p>这篇是我把 <code>Claude Code</code> 真正跑起来后，整理出的一套可复用流程。 不是“命令一贴就完事”，而是从安装、验证、固化配置到避坑都走一遍，确保你能稳定用起来。</p><h2 id="先说结论-推荐路径" tabindex="-1">先说结论（推荐路径） <a class="header-anchor" href="#先说结论-推荐路径" aria-label="Permalink to &quot;先说结论（推荐路径）&quot;">​</a></h2><ul><li>安装：<code>Node.js LTS</code> + <code>npm install -g @anthropic-ai/claude-code</code></li><li>配置：先用 <strong>PowerShell 临时环境变量</strong>验证，再决定是否永久化</li><li>启动：在项目根目录执行 <code>claude</code></li><li>核验：先过 <code>claude --version</code>，再确认能正常发起会话</li></ul><h2 id="_0-前置条件" tabindex="-1">0. 前置条件 <a class="header-anchor" href="#_0-前置条件" aria-label="Permalink to &quot;0. 前置条件&quot;">​</a></h2><p>开始前先确认这些条件：</p><ul><li>系统：Windows（示例基于 PowerShell）</li><li>Node.js：建议 LTS（18+，推荐 20+）</li><li>npm：可正常使用</li><li>你已准备好可用的 API 服务地址与 Token</li></ul><p>快速检查：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre></div><h2 id="_1-安装-claude-code" tabindex="-1">1. 安装 Claude Code <a class="header-anchor" href="#_1-安装-claude-code" aria-label="Permalink to &quot;1. 安装 Claude Code&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @anthropic-ai/claude-code</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>如果能看到版本号，CLI 本体就安装成功了。</p><h2 id="_2-配置环境变量-核心" tabindex="-1">2. 配置环境变量（核心） <a class="header-anchor" href="#_2-配置环境变量-核心" aria-label="Permalink to &quot;2. 配置环境变量（核心）&quot;">​</a></h2><p>最常见、最稳定的配置方式是两个环境变量：</p><ul><li><code>ANTHROPIC_BASE_URL</code></li><li><code>ANTHROPIC_AUTH_TOKEN</code></li></ul><blockquote><p>变量名中的下划线必须写对。 不要在博客、截图、仓库里暴露真实 Token。</p></blockquote><h3 id="_2-1-临时配置-建议先做" tabindex="-1">2.1 临时配置（建议先做） <a class="header-anchor" href="#_2-1-临时配置-建议先做" aria-label="Permalink to &quot;2.1 临时配置（建议先做）&quot;">​</a></h3><p>先在 PowerShell 里跑一遍临时配置，快速判断配置是否正确：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ANTHROPIC_BASE_URL </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://api.qinzhiai.com&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ANTHROPIC_AUTH_TOKEN </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;sk-你的API密钥&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">claude</span></span></code></pre></div><p>特点：</p><ul><li>仅当前终端会话有效</li><li>适合调试和排错</li><li>关闭窗口即失效，安全性更高</li></ul><h3 id="_2-2-永久配置-确认可用后再做" tabindex="-1">2.2 永久配置（确认可用后再做） <a class="header-anchor" href="#_2-2-永久配置-确认可用后再做" aria-label="Permalink to &quot;2.2 永久配置（确认可用后再做）&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ANTHROPIC_BASE_URL&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://api.qinzhiai.com&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ANTHROPIC_AUTH_TOKEN&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;sk-你的API密钥&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>执行后请关闭并重开终端，再运行 <code>claude</code>。</p><h2 id="_3-配置文件方案-可选-适合多项目" tabindex="-1">3. 配置文件方案（可选，适合多项目） <a class="header-anchor" href="#_3-配置文件方案-可选-适合多项目" aria-label="Permalink to &quot;3. 配置文件方案（可选，适合多项目）&quot;">​</a></h2><p>如果你希望“不同项目用不同节点”，可以改成项目级配置。</p><p>在项目根目录创建 <code>.claude/settings.json</code>：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;ANTHROPIC_BASE_URL&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://api.qinzhiai.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;ANTHROPIC_AUTH_TOKEN&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sk-你的APIKey&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;ANTHROPIC_MODEL&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;claude-sonnet-4-5&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>全局配置路径：</p><ul><li>Windows：<code>C:\\Users\\你的用户名\\.claude\\settings.json</code></li><li>macOS/Linux：<code>~/.claude/settings.json</code></li></ul><h2 id="_4-建议的实操顺序-少走弯路" tabindex="-1">4. 建议的实操顺序（少走弯路） <a class="header-anchor" href="#_4-建议的实操顺序-少走弯路" aria-label="Permalink to &quot;4. 建议的实操顺序（少走弯路）&quot;">​</a></h2><ol><li>先安装并确认 <code>claude --version</code></li><li>用临时变量跑通一次 <code>claude</code></li><li>再决定做永久变量还是项目级配置</li><li>最后再考虑可视化多节点管理工具</li></ol><p>这套顺序的核心价值是：每一步都可验证，问题定位非常快。</p><h2 id="_5-常见问题排查" tabindex="-1">5. 常见问题排查 <a class="header-anchor" href="#_5-常见问题排查" aria-label="Permalink to &quot;5. 常见问题排查&quot;">​</a></h2><h3 id="_5-1-版本正常-但无法启动会话" tabindex="-1">5.1 版本正常，但无法启动会话 <a class="header-anchor" href="#_5-1-版本正常-但无法启动会话" aria-label="Permalink to &quot;5.1 版本正常，但无法启动会话&quot;">​</a></h3><p>常见原因：</p><ul><li><code>ANTHROPIC_BASE_URL</code> 写错（协议、路径、域名）</li><li><code>ANTHROPIC_AUTH_TOKEN</code> 无效或有隐藏空格</li><li>你在旧终端里测试，没加载到新变量</li></ul><p>快速检查：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ANTHROPIC_BASE_URL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ANTHROPIC_AUTH_TOKEN</span></span></code></pre></div><h3 id="_5-2-永久变量设置后不生效" tabindex="-1">5.2 永久变量设置后不生效 <a class="header-anchor" href="#_5-2-永久变量设置后不生效" aria-label="Permalink to &quot;5.2 永久变量设置后不生效&quot;">​</a></h3><ul><li>重开终端</li><li>如果在 IDE 内置终端测试，必要时重启 IDE</li></ul><h3 id="_5-3-多个项目互相覆盖配置" tabindex="-1">5.3 多个项目互相覆盖配置 <a class="header-anchor" href="#_5-3-多个项目互相覆盖配置" aria-label="Permalink to &quot;5.3 多个项目互相覆盖配置&quot;">​</a></h3><p>优先使用项目级 <code>.claude/settings.json</code>，避免全局变量串用。</p><h2 id="_6-安全建议-不要跳过" tabindex="-1">6. 安全建议（不要跳过） <a class="header-anchor" href="#_6-安全建议-不要跳过" aria-label="Permalink to &quot;6. 安全建议（不要跳过）&quot;">​</a></h2><ul><li>不要把真实 Token 写进文档、截图、录屏</li><li>不要提交带凭证的 <code>.claude/settings.json</code></li><li>仓库建议加入忽略规则</li></ul><div class="language-gitignore vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">gitignore</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>.claude/settings.json</span></span></code></pre></div><h2 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to &quot;结语&quot;">​</a></h2><p><code>Claude Code</code> 真正的难点不是安装命令，而是“配置是否可验证、可复现、可维护”。 按“先临时验证 -&gt; 再永久固化 -&gt; 最后按项目管理”这条线走，基本能避开 90% 的坑。</p>`,48),n=[t];function h(p,o,d,k,c,r){return a(),i("div",null,n)}const g=s(l,[["render",h]]);export{E as __pageData,g as default};
